command:
// =========================
// FACTION ROLL TABLE GENERATOR
// Sandbox Generator
// Creates a reusable Foundry Roll Table
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

function pick(arr) {
    return arr[roll(arr.length) - 1];
}

const options = await Dialog.prompt({
    title: "Generate Faction Roll Table",
    content: `
    <p>How many factions do you want to generate?</p>
    <input id="count" type="number" value="3" min="1" max="50"/>

    <p>Roll Table Name:</p>
    <input id="tableName" type="text" value="Sandbox Factions"/>
    `,
    callback: html => ({
        count: Number(html.find("#count").val()),
                       tableName: html.find("#tableName").val()
    })
});

const factionTypes = [
    "City Faction",
"Castle / Noble House",
"Wizard Tower",
"Abbey / Religious Order",
"Intelligent Monster Lair",
"Criminal Organization",
"Guild",
"Dragon",
"Wizard"
];

const namePartsA = [
    "Ash", "Black", "Red", "Silver", "Golden", "Iron", "White", "Green",
"Storm", "Moon", "Sun", "Wolf", "Raven", "Oak", "Stone", "Blood",
"Dawn", "Dusk", "Hollow", "Thorn"
];

const namePartsB = [
    "Barrow", "Crown", "Fang", "Hand", "Banner", "Circle", "Order",
"House", "Brotherhood", "Syndicate", "Claw", "Flame", "Root",
"Tower", "Abbey", "Company", "Court", "Tribe", "Veil", "Gate"
];

const goals = [
    "Expand territory",
"Protect their domain",
"Control trade routes",
"Recover a lost relic",
"Destroy a rival faction",
"Gain political influence",
"Keep an ancient secret hidden",
"Secure magical resources",
"Defend their people",
"Exploit nearby settlements"
];

const resources = [
    "Soldiers",
"Gold",
"Magic",
"Religious authority",
"Spies",
"Monsters",
"Trade goods",
"Ancient knowledge",
"Fortified holdings",
"Local loyalty"
];

const problems = [
    "Internal betrayal",
"Resource shortage",
"Hostile neighbors",
"A missing leader",
"A cursed location",
"Growing unrest",
"Monster attacks",
"Debt",
"A rival claimant",
"A dangerous secret"
];

const attitudes = [
    "Aggressive",
"Suspicious",
"Pragmatic",
"Honorable",
"Secretive",
"Desperate",
"Greedy",
"Protective",
"Fanatical",
"Opportunistic"
];

let factions = [];

for (let i = 1; i <= options.count; i++) {
    const type = pick(factionTypes);
    const name = `The ${pick(namePartsA)} ${pick(namePartsB)}`;

    const goal = pick(goals);
    const resource = pick(resources);
    const problem = pick(problems);
    const attitude = pick(attitudes);

    const text =
    `${name} | Type: ${type} | Goal: ${goal} | Resource: ${resource} | Problem: ${problem} | Attitude: ${attitude}`;

    factions.push({
        number: i,
        name,
        type,
        goal,
        resource,
        problem,
        attitude,
        text
    });
}

// Delete old table with same name? No, safer to create a new one with timestamp if duplicate exists.
let tableName = options.tableName;
if (game.tables.getName(tableName)) {
    tableName = `${tableName} ${new Date().toLocaleTimeString()}`;
}

const table = await RollTable.create({
    name: tableName,
    formula: `1d${options.count}`,
        replacement: true,
        displayRoll: true
});

await table.createEmbeddedDocuments("TableResult", factions.map(f => ({
    type: CONST.TABLE_RESULT_TYPES.TEXT,
    text: f.text,
    range: [f.number, f.number],
    weight: 1,
    drawn: false
})));

let output = `
<h2>Faction Roll Table Created</h2>

<p><b>Table Name:</b> ${tableName}</p>
<p><b>Formula:</b> 1d${options.count}</p>

<hr>

<h3>Generated Factions</h3>
<ol>
${factions.map(f => `
    <li>
    <b>${f.name}</b><br>
    <b>Type:</b> ${f.type}<br>
    <b>Goal:</b> ${f.goal}<br>
    <b>Resource:</b> ${f.resource}<br>
    <b>Problem:</b> ${f.problem}<br>
    <b>Attitude:</b> ${f.attitude}
    </li>
    `).join("")}
    </ol>

    <hr>

    <p><i>You can now roll on this table whenever a hex, dungeon room, encounter, settlement, or event involves a faction.</i></p>
    `;

    ChatMessage.create({
        speaker: ChatMessage.getSpeaker(),
                       content: output
    });
